@namespace sv_b3d79cb44ecc4f1c8a30dc0dd17882e7.Components.Pages.Board

<div class="task-card">
    <h4 class="task-card__title">@Task.Title</h4>
    <p class="task-card__assignee">@Task.Assignee</p>
    <span class="task-card__priority task-card__priority--@Task.Priority.ToLower()">@Task.Priority</span>
    <span class="task-card__due">@Task.DueDate.ToString("MMM dd")</span>
    <div class="task-card__actions">
        @if (CanMoveLeft)
        {
            <button class="task-card__btn task-card__btn--left" @onclick="OnMoveLeftClick">Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="task-card__btn task-card__btn--right" @onclick="OnMoveRightClick">Move Right</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private async System.Threading.Tasks.Task OnMoveLeftClick() => await OnMoveLeft.InvokeAsync(Task.Id);
    private async System.Threading.Tasks.Task OnMoveRightClick() => await OnMoveRight.InvokeAsync(Task.Id);
}

@namespace sv_b3d79cb44ecc4f1c8a30dc0dd17882e7.Components.Pages.Board

<div class="add-task-form">
    <input type="text" placeholder="Title" @bind="title" class="add-task-form__input" />
    <input type="text" placeholder="Assignee" @bind="assignee" class="add-task-form__input" />
    <select @bind="priority" class="add-task-form__select">
        <option value="High">High</option>
        <option value="Medium">Medium</option>
        <option value="Low">Low</option>
    </select>
    <input type="date" @bind="dueDate" class="add-task-form__input" />
    <div class="add-task-form__actions">
        <button class="add-task-form__btn add-task-form__btn--save" @onclick="HandleSave" disabled="@isSaving">Save</button>
        <button class="add-task-form__btn add-task-form__btn--cancel" @onclick="HandleCancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@namespace sv_b3d79cb44ecc4f1c8a30dc0dd17882e7.Components.Pages.Board

<div class="kanban-column">
    <div class="kanban-column__header">
        <h3>@Title (@Tasks.Count)</h3>
    </div>
    <div class="kanban-column__body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <div class="kanban-column__footer">
        @if (showForm)
        {
            <AddTaskForm Status="@Status"
                         OnTaskCreated="HandleTaskCreated"
                         OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="kanban-column__add-btn" @onclick="() => showForm = true">Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnTaskCreated.InvokeAsync(task);
        showForm = false;
    }
}

