    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}
