@namespace sv_b3d79cb44ecc4f1c8a30dc0dd17882e7.Components.Pages.Board

<div class="kanban-column">
    <div class="kanban-column__header">
        <h3>@Title (@Tasks.Count)</h3>
    </div>
    <div class="kanban-column__body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <div class="kanban-column__footer">
        @if (showForm)
        {
            <AddTaskForm Status="@Status"
                         OnTaskCreated="HandleTaskCreated"
                         OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="kanban-column__add-btn" @onclick="() => showForm = true">Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnTaskCreated.InvokeAsync(task);
        showForm = false;
    }
}

