@page "/board"
@namespace sv_b3d79cb44ecc4f1c8a30dc0dd17882e7.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p class="board-message">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <p class="board-message board-message--error">@errorMessage</p>
}
else
{
    <BoardStatsBar Total="@allTasks.Count"
                   ToDo="@CountByStatus("To Do")"
                   InProgress="@CountByStatus("In Progress")"
                   DoneCount="@CountByStatus("Done")"
                   Overdue="@allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="HandleSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn Title="To Do"
                      Status="To Do"
                      Tasks="@GetFilteredTasks("To Do")"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="@(id => MoveTask(id, "In Progress"))"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn Title="In Progress"
                      Status="In Progress"
                      Tasks="@GetFilteredTasks("In Progress")"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="@(id => MoveTask(id, "To Do"))"
                      OnMoveRight="@(id => MoveTask(id, "Done"))"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn Title="Done"
                      Status="Done"
                      Tasks="@GetFilteredTasks("Done")"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="@(id => MoveTask(id, "In Progress"))"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status) =>
        allTasks.Count(t => t.Status == status);

    private List<TaskItem> GetFilteredTasks(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchText) ||
                        t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(TaskItem formData)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

